package format

import (
	"testing"

	"github.com/google/go-cmp/cmp"
	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
)

func TestCompactDiffFormatter(t *testing.T) {
	tests := map[string]struct {
		plan *plans.Plan
		want string
	}{
		"empty plan": {
			plan: &plans.Plan{
				Changes: plans.NewChangesSrc(),
			},
			want: "",
		},
		"single create": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
								},
							},
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
						},
					},
				},
			},
			want: "  [green]+[reset] aws_instance.example\n\nSummary:\n  + 1 resource(s) added\n",
		},
		"mixed changes": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "create_me",
									},
								},
							},
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
						},
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_security_group",
										Name: "update_me",
									},
								},
							},
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Update,
							},
						},
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_vpc",
										Name: "delete_me",
									},
								},
							},
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Delete,
							},
						},
					},
				},
			},
			want: "  [green]+[reset] aws_instance.create_me\n  [yellow]~[reset] aws_security_group.update_me\n  [red]-[reset] aws_vpc.delete_me\n\nSummary:\n  + 1 resource(s) added\n  ~ 1 resource(s) changed\n  - 1 resource(s) destroyed\n",
		},
		"nil plan": {
			plan: nil,
			want: "",
		},
	}

	formatter := &CompactDiffFormatter{}

	for name, test := range tests {
		t.Run(name, func(t *testing.T) {
			got := formatter.Format(test.plan, nil)
			if diff := cmp.Diff(test.want, got); diff != "" {
				t.Errorf("Format() output mismatch (-want +got):\n%s", diff)
			}
		})
	}
}

